import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

import org.apache.commons.text.StringEscapeUtils; // Import StringEscapeUtils from Apache Commons Text

public class InputHandler extends HttpServlet {
    public void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize and escape user input to prevent XSS
        String safeUserInput = StringEscapeUtils.escapeHtml4(userInput);

        // Send a secure response
        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<p>User Input: " + safeUserInput + "</p>"); // Safe from XSS
        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
